import { Routes } from '@angular/router';
import { authGuard } from './core/guards/auth.guard';
import { roleGuard } from './core/guards/role.guard';
import { LayoutComponent } from './shared/layout.component';

const PLANNER = { roles: ['planner'] as const };

/**
 * SiteView route tree. Hash routing is configured in app.config.ts.
 * Login/signup render standalone; everything else is wrapped by LayoutComponent
 * and guarded by authGuard. Both roles (viewer + planner) may read every view;
 * planner-only edit controls are hidden inside each component. Admin settings is
 * planner-only at the route level. Each route carries `data.flow { node, ... }`.
 */
export const routes: Routes = [
  {
    path: 'login',
    loadComponent: () => import('./pages/login/login.component').then((m) => m.LoginComponent),
    data: { flow: { node: 'login', entry: true, edgesTo: ['projects', 'signup'] } },
  },
  {
    path: 'signup',
    loadComponent: () => import('./pages/signup/signup.component').then((m) => m.SignupComponent),
    data: { flow: { node: 'signup', edgesTo: ['projects', 'login'] } },
  },
  {
    path: '',
    component: LayoutComponent,
    children: [
      { path: '', pathMatch: 'full', redirectTo: 'projects' },

      // ---- Projects list (any logged-in user) ----
      {
        path: 'projects',
        canActivate: [authGuard],
        loadComponent: () =>
          import('./pages/projects-list/projects-list.component').then((m) => m.ProjectsListComponent),
        data: { flow: { node: 'projects', showInNavbar: true, edgesTo: ['project-detail'] } },
      },

      // ---- Project detail shell + child feature views ----
      {
        path: 'projects/:id',
        canActivate: [authGuard],
        loadComponent: () =>
          import('./pages/project-detail/project-detail.component').then((m) => m.ProjectDetailComponent),
        data: { flow: { node: 'project-detail', edgesTo: ['dashboard', 'schedule', 'milestones', 'budget', 'siteplan', 'projects'] } },
        children: [
          { path: '', pathMatch: 'full', redirectTo: 'dashboard' },
          {
            path: 'dashboard',
            loadComponent: () =>
              import('./features/dashboard/dashboard.component').then((m) => m.DashboardComponent),
            data: { flow: { node: 'dashboard', edgesTo: ['schedule', 'budget', 'siteplan'] } },
          },
          {
            path: 'schedule',
            loadComponent: () =>
              import('./features/gantt/gantt.component').then((m) => m.GanttComponent),
            data: { flow: { node: 'schedule', edgesTo: ['dashboard'] } },
          },
          {
            path: 'milestones',
            loadComponent: () =>
              import('./features/milestones/milestones.component').then((m) => m.MilestonesComponent),
            data: { flow: { node: 'milestones', edgesTo: ['dashboard'] } },
          },
          {
            path: 'budget',
            loadComponent: () =>
              import('./features/budget/budget-burndown.component').then((m) => m.BudgetBurndownComponent),
            data: { flow: { node: 'budget', edgesTo: ['dashboard'] } },
          },
          {
            path: 'siteplan',
            loadComponent: () =>
              import('./features/siteplan/siteplan.component').then((m) => m.SiteplanComponent),
            data: { flow: { node: 'siteplan', edgesTo: ['dashboard'] } },
          },
        ],
      },

      // ---- Admin settings (planner only) ----
      {
        path: 'admin/settings',
        canActivate: [authGuard, roleGuard],
        loadComponent: () =>
          import('./pages/settings/settings.component').then((m) => m.SettingsComponent),
        data: { roles: PLANNER.roles, flow: { node: 'settings', showInNavbar: true, scope: 'planner', edgesTo: ['projects'] } },
      },
    ],
  },

  { path: '**', redirectTo: '' },
];
